## 3. Server Architecture

```python
class CollaborationServer:
    def __init__(self):
        self.document_sessions = {}  # doc_id -> DocumentSession
        self.redis = RedisClient()
        self.db = DocumentStore()

    async def handle_connection(self, websocket, doc_id, user_id):
        session = await self.get_or_create_session(doc_id)
        await session.add_client(websocket, user_id)

        try:
            # Send current document state
            doc_state = await self.db.get_document(doc_id)
            await websocket.send(json.dumps({
                'type': 'SYNC',
                'document': doc_state.content,
                'version': doc_state.version
            }))

            # Handle incoming messages
            async for message in websocket:
                await self.handle_operation(
                    json.loads(message), 
                    session, 
                    user_id
                )
        finally:
            await session.remove_client(user_id)

    async def handle_operation(self, operation, session, user_id):
        async with session.lock:
            # 1. Validate operation
            if not self.validate_operation(operation):
                await self.send_error(user_id, "Invalid operation")
                return

            # 2. Transform against operations since client's version
            server_ops = await self.get_ops_since(
                session.doc_id, 
                operation['version']
            )

            transformed_op = operation
            for server_op in server_ops:
                transformed_op = transform(transformed_op, server_op)

            # 3. Apply to document
            new_version = await self.apply_operation(
                session.doc_id, 
                transformed_op
            )

            # 4. Acknowledge to sender
            await session.send_to_user(user_id, {
                'type': 'ACK',
                'operationId': operation['id'],
                'newVersion': new_version
            })

            # 5. Broadcast to other clients
            await session.broadcast_except(user_id, {
                'type': 'REMOTE_OP',
                'operation': transformed_op,
                'version': new_version,
                'userId': user_id
            })

            # 6. Persist asynchronously
            await self.persist_operation(session.doc_id, transformed_op)


class DocumentSession:
    def __init__(self, doc_id):
        self.doc_id = doc_id
        self.clients = {}  # user_id -> websocket
        self.lock = asyncio.Lock()
        self.current_version = 0
        self.cursors = {}  # user_id -> cursor_position

    async def broadcast_except(self, exclude_user_id, message):
        tasks = [
            ws.send(json.dumps(message))
            for uid, ws in self.clients.items()
            if uid != exclude_user_id
        ]
        await asyncio.gather(*tasks, return_exceptions=True)

    async def broadcast_cursor(self, user_id, position):
        """Share cursor positions for presence awareness"""
        self.cursors[user_id] = position
        await self.broadcast_except(user_id, {
            'type': 'CURSOR_UPDATE',
            'userId': user_id,
            'position': position,
            'color': self.get_user_color(user_id)
        })
```

