## 4. Data Storage Design

```sql
-- Documents table
CREATE TABLE documents (
    id          UUID PRIMARY KEY,
    title       VARCHAR(500),
    owner_id    UUID,
    content     TEXT,           -- Current snapshot
    version     BIGINT,
    created_at  TIMESTAMP,
    updated_at  TIMESTAMP
);

-- Operation log for history and conflict resolution
CREATE TABLE operations (
    id          UUID PRIMARY KEY,
    doc_id      UUID REFERENCES documents(id),
    user_id     UUID,
    version     BIGINT,
    op_type     VARCHAR(20),    -- INSERT | DELETE | FORMAT
    position    INT,
    content     TEXT,
    metadata    JSONB,          -- formatting, attributes
    created_at  TIMESTAMP,
    INDEX idx_doc_version (doc_id, version)
);

-- Snapshots for fast loading (every N operations)
CREATE TABLE snapshots (
    id          UUID PRIMARY KEY,
    doc_id      UUID,
    version     BIGINT,
    content     TEXT,
    created_at  TIMESTAMP
);

-- Collaborators and permissions
CREATE TABLE document_permissions (
    doc_id      UUID,
    user_id     UUID,
    role        VARCHAR(20),    -- OWNER | EDITOR | VIEWER | COMMENTER
    PRIMARY KEY (doc_id, user_id)
);
```

