## 5. Presence System — Final Design

```javascript
class PresenceSystem {
    constructor(provider, editor, currentUser) {
        this.awareness = provider.awareness;
        this.editor = editor;
        this.user = currentUser;
        this.remoteUsers = new Map();

        // Throttle cursor updates — max 10/sec
        this.sendCursorUpdate = throttle(
            this._sendCursorUpdate.bind(this), 
            100
        );

        this.awareness.on('change', this.handleAwarenessChange.bind(this));
        this.editor.on('selectionUpdate', this.sendCursorUpdate.bind(this));
    }

    _sendCursorUpdate() {
        const { from, to } = this.editor.state.selection;

        this.awareness.setLocalStateField('cursor', {
            anchor: Y.createRelativePositionFromTypeIndex(
                this.ytext, from
            ),
            head: Y.createRelativePositionFromTypeIndex(
                this.ytext, to
            )
        });
    }

    handleAwarenessChange({ added, updated, removed }) {
        const states = this.awareness.getStates();

        // Handle new/updated users
        [...added, ...updated].forEach(clientId => {
            if (clientId === this.awareness.clientID) return;

            const state = states.get(clientId);
            if (!state?.user) return;

            this.remoteUsers.set(clientId, state.user);

            if (state.cursor) {
                this.renderRemoteCursor(clientId, state);
            }
        });

        // Handle departed users
        removed.forEach(clientId => {
            this.remoteUsers.delete(clientId);
            this.removeRemoteCursor(clientId);
        });

        this.updateCollaboratorPanel();
    }

    renderRemoteCursor(clientId, state) {
        const { user, cursor } = state;

        // Convert relative positions to absolute
        const anchor = Y.createAbsolutePositionFromRelativePosition(
            cursor.anchor, this.ydoc
        );
        const head = Y.createAbsolutePositionFromRelativePosition(
            cursor.head, this.ydoc
        );

        if (!anchor || !head) return;

        this.editor.setCursorDecoration(clientId, {
            from: anchor.index,
            to: head.index,
            color: user.color,
            label: user.name,
            className: `remote-cursor-${clientId}`
        });
    }

    updateCollaboratorPanel() {
        const collaborators = Array.from(this.remoteUsers.values());
        this.ui.renderCollaboratorAvatars(collaborators);
        this.ui.updateCount(collaborators.length + 1); // +1 for self
    }
}
