## 6. Security — Final Design

```python
class SecurityLayer:

    # Connection security
    async def authenticate_websocket(self, request):
        token = (
            request.headers.get('Authorization', '').replace('Bearer ', '')
            or request.query_params.get('token')  # Fallback for WS
        )

        try:
            payload = jwt.decode(token, SECRET_KEY, algorithms=['RS256'])
            user = await self.db.get_user(payload['sub'])
            return user
        except jwt.ExpiredSignatureError:
            raise AuthError("Token expired")
        except jwt.InvalidTokenError:
            raise AuthError("Invalid token")

    # Operation security
    async def validate_update(self, update_bytes, user_id, doc_id):
        # Size limit
        if len(update_bytes) > MAX_UPDATE_BYTES:  # e.g., 1MB
            raise SecurityError("Update too large")

        # Permission check on every update
        permission = await self.get_permission(user_id, doc_id)
        if permission not in ('OWNER', 'EDITOR'):
            raise PermissionError("Insufficient permissions")

        # Validate it's a legitimate Yjs update (not malformed)
        try:
            Y.decodeUpdate(update_bytes)
        except Exception:
            raise SecurityError("Malformed update")

        return True

    # Rate limiting
    async def check_rate_limits(self, user_id, doc_id):
        limits = [
            # Per-user global limit
            (f"rate:user:{user_id}", 100, 1),           # 100 ops/sec
            # Per-user per-document limit
            (f"rate:user:{user_id}:doc:{doc_id}", 50, 1), # 50 ops/sec
            # Per-document total limit (all users)
            (f"rate:doc:{doc_id}", 500, 1),              # 500 ops/sec
        ]

        for key, max_count, window_secs in limits:
            count = await self.redis.incr(key)
            if count == 1:
                await self.redis.expire(key, window_secs)
            if count > max_count:
                raise RateLimitError(f"Rate limit exceeded: {key}")

    # Encryption at rest
    def encrypt_snapshot(self, doc_id, snapshot_bytes):
        key = self.kms.get_or_create_key(f"doc:{doc_id}")
        nonce = os.urandom(12)
        cipher = AESGCM(key)
        encrypted = cipher.encrypt(nonce, snapshot_bytes, None)
        return nonce + encrypted  # Prepend nonce for decryption
