```javascript
import * as Y from 'yjs'
import { WebsocketProvider } from 'y-websocket'
import { prosemirrorPlugin } from 'y-prosemirror'

class CollaborativeDocument {
    constructor(docId, currentUser) {
        this.docId = docId;
        this.user = currentUser;

        // Yjs document — single source of CRDT truth
        this.ydoc = new Y.Doc();

        // Shared types
        this.ytext    = this.ydoc.getText('content');
        this.ymeta    = this.ydoc.getMap('metadata');
        this.ycomments = this.ydoc.getArray('comments');

        // WebSocket sync — handles reconnection automatically
        this.provider = new WebsocketProvider(
            'wss://collab.yourdomain.com',
            `doc-${docId}`,
            this.ydoc
        );

        // Awareness — presence, cursors, selections
        this.provider.awareness.setLocalStateField('user', {
            id:     currentUser.id,
            name:   currentUser.name,
            color:  currentUser.color,
            cursor: null
        });

        // Offline persistence — automatic merge on reconnect
        this.persistence = new IndexeddbPersistence(
            `doc-${docId}`, 
            this.ydoc
        );

        this.setupEditor();
        this.setupPresence();
    }

    setupEditor() {
        // ProseMirror binding — production-grade rich text
        this.editor = new EditorView(document.querySelector('#editor'), {
            state: EditorState.create({
                plugins: [
                    prosemirrorPlugin(this.ydoc),
                    yCursorPlugin(this.provider.awareness)
                ]
            })
        });
    }

    setupPresence() {
        this.provider.awareness.on('change', () => {
            const states = this.provider.awareness.getStates();
            this.renderCollaborators(states);
        });
    }

    renderCollaborators(states) {
        const collaborators = Array.from(states.entries())
            .filter(([clientId]) => clientId !== this.ydoc.clientID)
            .map(([_, state]) => state.user);

        this.ui.updateCollaboratorList(collaborators);
    }

    destroy() {
        this.provider.destroy();
        this.persistence.destroy();
        this.editor.destroy();
    }
}
