## 2. Server Architecture — Final Design

```python
import asyncio
import json
from dataclasses import dataclass, field
from typing import Dict, Set
from uuid import UUID, uuid4

class CollaborationServer:
    """
    Server acts as:
    1. WebSocket hub (routing messages)
    2. Persistence coordinator
    3. Presence broadcaster
    4. Permission enforcer

    NOT as conflict resolver — Yjs handles that.
    This is the key architectural shift from my first answer.
    """

    def __init__(self):
        self.sessions: Dict[str, DocumentSession] = {}
        self.redis   = RedisCluster()
        self.db      = DocumentStore()
        self.metrics = MetricsCollector()
        self.auth    = AuthService()

    async def handle_connection(self, websocket, doc_id, token):
        # 1. Authenticate
        user = await self.auth.verify_token(token)
        if not user:
            await websocket.close(code=4001, reason="Unauthorized")
            return

        # 2. Authorize
        permission = await self.db.get_permission(user.id, doc_id)
        if not permission:
            await websocket.close(code=4003, reason="Forbidden")
            return

        # 3. Rate limit
        if not await self.check_rate_limit(user.id):
            await websocket.close(code=4029, reason="Too Many Requests")
            return

        # 4. Join session
        session = await self.get_or_create_session(doc_id)
        await session.add_client(websocket, user, permission)

        self.metrics.track('connection_opened', doc_id=doc_id)

        try:
            async for raw_message in websocket:
                await self.handle_message(
                    raw_message, session, user, permission
                )
        except WebSocketDisconnect:
            pass
        finally:
            await session.remove_client(user.id)
            self.metrics.track('connection_closed', doc_id=doc_id)

    async def handle_message(self, raw_message, session, user, permission):
        try:
            message = self.parse_and_validate(raw_message)
        except ValidationError as e:
            await session.send_to_user(user.id, {
                'type': 'ERROR',
                'code': 'INVALID_MESSAGE',
                'detail': str(e)
            })
            return

        match message['type']:
            case 'SYNC_STEP_1':
                # Yjs sync protocol step 1
                await self.handle_sync_step1(message, session, user)

            case 'SYNC_STEP_2':
                # Yjs sync protocol step 2
                await self.handle_sync_step2(message, session, user)

            case 'UPDATE':
                # Yjs document update (CRDT delta)
                if permission == 'VIEWER':
                    return  # Silently ignore
                await self.handle_update(message, session, user)

            case 'AWARENESS':
                # Cursor/presence update
                await self.handle_awareness(message, session, user)

            case 'QUERY_HISTORY':
                await self.handle_history_query(message, session, user)

    async def handle_update(self, message, session, user):
        update = message['update']  # Binary Yjs update

        # 1. Validate update size
        if len(update) > MAX_UPDATE_SIZE:
            raise UpdateTooLarge()

        # 2. Persist asynchronously (don't block broadcast)
        asyncio.create_task(
            self.persist_update(session.doc_id, update, user.id)
        )

        # 3. Broadcast to other clients in this server
        await session.broadcast_except(user.id, {
            'type': 'UPDATE',
            'update': update
        })

        # 4. Publish to Redis for other servers
        await self.redis.publish(
            f'doc:{session.doc_id}:updates',
            json.dumps({'update': update, 'from_user': str(user.id)})
        )

        self.metrics.track('update_processed',
            doc_id=session.doc_id,
            size=len(update)
        )

    async def persist_update(self, doc_id, update, user_id):
        """
        Persist with snapshot compaction strategy.
        Every 100 updates, merge into a new snapshot.
        """
        op_count = await self.db.append_update(doc_id, update, user_id)

        if op_count % SNAPSHOT_INTERVAL == 0:
            asyncio.create_task(
                self.create_snapshot(doc_id)
            )


@dataclass
class DocumentSession:
    doc_id: str
    clients: Dict[str, WebSocket] = field(default_factory=dict)
    permissions: Dict[str, str] = field(default_factory=dict)
    awareness_states: Dict[str, dict] = field(default_factory=dict)

    async def add_client(self, websocket, user, permission):
        self.clients[user.id] = websocket
        self.permissions[user.id] = permission

        # Send current document state (Yjs sync protocol)
        snapshot = await self.get_current_snapshot()
        await websocket.send(json.dumps({
            'type': 'SYNC_STEP_1',
            'stateVector': snapshot.state_vector
        }))

    async def remove_client(self, user_id):
        self.clients.pop(user_id, None)
        self.permissions.pop(user_id, None)
        self.awareness_states.pop(user_id, None)

        # Notify others this user left
        await self.broadcast_except(user_id, {
            'type': 'AWARENESS',
            'removed': [user_id]
        })

    async def broadcast_except(self, exclude_id, message):
        payload = json.dumps(message)
        results = await asyncio.gather(*[
            ws.send(payload)
            for uid, ws in self.clients.items()
            if uid != exclude_id
        ], return_exceptions=True)

        # Handle failed sends (disconnected clients)
        for uid, result in zip(
            [u for u in self.clients if u != exclude_id], 
            results
        ):
            if isinstance(result, Exception):
                await self.remove_client(uid)
