-- Core document store
CREATE TABLE documents (
    id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    title           VARCHAR(500) NOT NULL,
    owner_id        UUID NOT NULL REFERENCES users(id),
    snapshot        BYTEA,              -- Latest Yjs document state
    snapshot_version BIGINT DEFAULT 0,
    word_count      INT DEFAULT 0,
    size_bytes      INT DEFAULT 0,
    is_deleted      BOOLEAN DEFAULT FALSE,
    created_at      TIMESTAMPTZ DEFAULT NOW(),
    updated_at      TIMESTAMPTZ DEFAULT NOW()
);

-- Append-only operation log (Cassandra schema)
CREATE TABLE document_updates (
    doc_id          UUID,
    sequence_num    BIGINT,
    user_id         UUID,
    update_data     BLOB,               -- Binary Yjs update
    update_size     INT,
    client_id       TEXT,               -- Yjs client ID
    created_at      TIMESTAMP,
    PRIMARY KEY (doc_id, sequence_num)
) WITH CLUSTERING ORDER BY (sequence_num ASC)
  AND compaction = {'class': 'TimeWindowCompactionStrategy'};

-- Periodic snapshots for fast loading
CREATE TABLE document_snapshots (
    doc_id          UUID,
    version         BIGINT,
    snapshot_data   BLOB,               -- Full Yjs state
    update_count    INT,                -- Updates merged into this
    created_at      TIMESTAMP,
    PRIMARY KEY (doc_id, version)
) WITH CLUSTERING ORDER BY (version DESC);

-- Fine-grained permissions
CREATE TABLE document_permissions (
    doc_id          UUID,
    user_id         UUID,
    role            VARCHAR(20),        -- OWNER|EDITOR|COMMENTER|VIEWER
    granted_by      UUID,
    granted_at      TIMESTAMPTZ DEFAULT NOW(),
    expires_at      TIMESTAMPTZ,        -- Optional expiry
    PRIMARY KEY (doc_id, user_id)
);

-- Share links
CREATE TABLE share_links (
    token           VARCHAR(64) PRIMARY KEY,
    doc_id          UUID NOT NULL,
    role            VARCHAR(20) NOT NULL,
