## 4. Offline Support — Final Design

```javascript
class OfflineFirstDocument {
    constructor(docId, userId) {
        this.ydoc = new Y.Doc();

        // Layer 1: IndexedDB persistence (immediate, local)
        this.localPersistence = new IndexeddbPersistence(
            `doc-${docId}-${userId}`,
            this.ydoc
        );

        // Layer 2: WebSocket sync (when online)
        this.networkProvider = new WebsocketProvider(
            'wss://collab.yourdomain.com',
            `doc-${docId}`,
            this.ydoc,
            {
                connect: navigator.onLine,
                resyncInterval: 5000,
                maxBackoffTime: 30000
            }
        );

        this.setupConnectivityHandling();
    }

    setupConnectivityHandling() {
        // Network status monitoring
        window.addEventListener('online', () => {
            this.networkProvider.connect();
            this.ui.showStatus('Reconnecting...');
        });

        window.addEventListener('offline', () => {
            this.ui.showStatus('Editing offline — changes saved locally');
        });

        // Provider status
        this.networkProvider.on('status', ({ status }) => {
            switch(status) {
                case 'connected':
                    this.ui.showStatus('All changes saved');
                    break;
                case 'connecting':
                    this.ui.showStatus('Syncing...');
                    break;
                case 'disconnected':
                    this.ui.showStatus('Offline — changes saved locally');
                    break;
            }
        });

        // Sync complete
        this.localPersistence.on('synced', () => {
            // Local state loaded — safe to show editor
            this.ui.hideLoadingSpinner();
        });
    }

    /*
     * Key insight: Yjs handles ALL merge logic automatically.
     * When reconnecting, Yjs exchanges state vectors with server,
     * identifies missing updates, and merges them — guaranteed
     * to converge to same state regardless of offline duration.
     * No custom merge logic needed.
     */
}
